/*
 * sinhf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sinhf  (test_sinhf_opt.elf)
 *   2. Linked with toolchain's default sinhf        (test_sinhf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = sinhf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: sinh(x) ~ x */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float vals[] = {
        0.5f,  /* sinh(0.5) ~ 0.521 */
        1.0f,  /* sinh(1) ~ 1.175 */
        1.5f,  /* sinh(1.5) ~ 2.301 */
        2.0f,  /* sinh(2) ~ 3.627 */
        -0.5f,
        -1.0f,
        -1.5f,
        -2.0f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large arguments (approaching overflow ~88.7) */
static void test_large(void)
{
    float vals[] = {
        10.0f, 20.0f, 50.0f, 80.0f, 88.0f, 88.7f, 88.72f,
        -10.0f, -20.0f, -50.0f, -88.0f, -88.7f,
        100.0f, -100.0f,  /* overflow */
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Transition around overflow threshold */
static void test_threshold(void)
{
    float base = 88.7f;
    float offsets[] = { -0.1f, -0.01f, 0.0f, 0.01f, 0.1f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    for (int j = 0; j < noff; j++)
        emit(base + offsets[j]);

    base = -88.7f;
    for (int j = 0; j < noff; j++)
        emit(base + offsets[j]);
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        0.125f, 0.25f, 0.375f, 0.625f, 0.75f, 0.875f,
        u2f(0x3f490fdbu), /* pi/4 */
        u2f(0x3fc90fdbu), /* pi/2 */
        4.0f, 16.0f, 64.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [0, 88.7] and [-88.7, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 88.7f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 88.7] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-88.7, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_threshold();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

