static void test_special_base(void)
{
    float exponents[] = { 0.0f, 1.0f, 2.0f, 0.5f, -1.0f };
    int ne = sizeof(exponents) / sizeof(exponents[0]);

    for (int j = 0; j < ne; j++) {
        emit(0.0f, exponents[j]);        /* 0^exp */
        emit(-0.0f, exponents[j]);       /* -0^exp */
    }

    /* Special exponent values */
    emit(2.0f, 0.0f);     /* x^0 */
    emit(10.0f, 0.0f);    /* x^0 */
