/*
 * frexpf() test harness — prints (input_hex, mantissa_hex, exponent) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly frexpf  (test_frexpf_opt.elf)
 *   2. Linked with toolchain's default frexpf        (test_frexpf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    int ex;
    float r = frexpf(x, &ex);
    printf("%08lx %08lx %d\n",
           (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: denormals */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-30f);
    emit(-1.0e-30f);
}

/* 3. Known values with specific exponents */
static void test_known(void)
{
    float vals[] = {
        0.5f, -0.5f,      /* exp = 0 */
        1.0f, -1.0f,      /* exp = 1 */
        1.5f, -1.5f,      /* exp = 1 */
        2.0f, -2.0f,      /* exp = 2 */
        3.14159265f, -3.14159265f,
        100.0f, -100.0f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        1000.0f, -1000.0f,
        1.0e10f, -1.0e10f,
        1.0e20f, -1.0e20f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Powers of 2 (pure exponent) */
static void test_powers_of_2(void)
{
    for (int i = -10; i <= 10; i++) {
        float v = powf(2.0f, (float)i);
        emit(v);
        emit(-v);
    }
}

/* 6. Worst-case mantissa values */
static void test_hard(void)
{
    float cases[] = {
        0.125f, 0.25f, 0.375f, 0.5f, 0.625f, 0.75f, 0.875f, 0.999f,
        1.001f, 1.125f, 1.25f, 1.5f, 1.75f, 1.999f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [0.5, 2) mantissa range with integer base exponents */
static void test_sweep(void)
{
    float lo = 0.5f, hi = 2.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);

    /* Negative */
    for (int i = 0; i <= nsteps; i++)
        emit(-(lo + (float)i * step));
