input.new_string:
/*
 * modff() test harness — prints (input_hex, integer_hex, fraction_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly modff  (test_modff_opt.elf)
 *   2. Linked with toolchain's default modff        (test_modff_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float ipart;
    float fpart = modff(x, &ipart);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(ipart),
           (unsigned long)f2u(fpart));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
}

/* 3. Integer and fractional parts */
static void test_known(void)
{
    float vals[] = {
        0.5f, -0.5f,      /* int=0, frac=±0.5 */
        1.5f, -1.5f,      /* int=±1, frac=±0.5 */
        2.7f, -2.7f,      /* int=±2, frac=±0.7 */
        3.14159265f, -3.14159265f,
        10.0f, -10.0f,    /* pure integer */
        10.5f, -10.5f,
        100.3f, -100.3f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        1000.0f, -1000.0f,
        1000.5f, -1000.5f,
        1.0e10f, -1.0e10f,
        1.0e20f, -1.0e20f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Pure fractional values (int = 0) */
static void test_fractional(void)
{
    float vals[] = {
        0.1f, -0.1f,
        0.25f, -0.25f,
        0.5f, -0.5f,
        0.75f, -0.75f,
        0.99f, -0.99f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        0.125f, 0.25f, 0.375f, 0.625f, 0.75f, 0.875f, 0.999f,
        1.125f, 2.25f, 3.375f, 4.5f, 5.75f, 9.875f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Integer values [0, 10] with small offsets */
static void test_integer_offsets(void)
{
    for (int i = 0; i <= 10; i++) {
        float base = (float)i;
        emit(base - 0.001f);
        emit(base);
        emit(base + 0.001f);
    }

    for (int i = 0; i >= -10; i--) {
        float base = (float)i;
        emit(base - 0.001f);
        emit(base);
        emit(base + 0.001f);
    }
}

/* 8. Sample [0, 1) every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b < end; b += 4194304)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_fractional();
    test_hard();
    test_integer_offsets();
    test_exhaustive_small();
    return 0;
}

