/*
 * fmodf() test harness — prints (input_hex, divisor_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fmodf  (test_fmodf_opt.elf)
 *   2. Linked with toolchain's default fmodf        (test_fmodf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x, float y)
{
    float r = fmodf(x, y);
    printf("%08lx %08lx %08lx\n",
           (unsigned long)f2u(x), (unsigned long)f2u(y), (unsigned long)f2u(r));
}

static void emit_u(uint32_t x_bits, uint32_t y_bits)
{
    emit(u2f(x_bits), u2f(y_bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f, 1.0f);
    emit(-0.0f, 1.0f);
    emit(1.0f, 0.0f);  /* fmod(x, 0) = NaN */

    /* NaN cases */
    emit_u(0x7fc00000u, 1.0f);  /* qNaN as numerator */
    emit(1.0f, u2f(0x7fc00000u));  /* qNaN as denominator */

    /* Infinity cases */
    emit_u(0x7f800000u, 1.0f);  /* Inf mod 1 = NaN */
    emit_u(0xff800000u, 1.0f);  /* -Inf mod 1 = NaN */
    emit(1.0f, u2f(0x7f800000u));  /* 1 mod Inf = 1 */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    emit(u2f(0x00000001u), 1.0f);
    emit(u2f(0x80000001u), 1.0f);
    emit(1.0f, FLT_MIN);
    emit(-1.0f, FLT_MIN);
}

/* 3. Exact divisions (x mod y where y divides x) */
static void test_exact(void)
{
    float vals[] = { 1.0f, 2.0f, 3.0f, 4.0f, 5.0f };
    int n = sizeof(vals) / sizeof(vals[0]);

    for (int i = 0; i < n; i++) {
        emit(vals[i], vals[i]);       /* x mod x = 0 */
        for (int j = i + 1; j < n; j++) {
            emit(vals[i] * vals[j], vals[j]);  /* (a*b) mod b = 0 */
        }
    }
}

/* 4. Non-exact divisions */
static void test_remainder(void)
{
    float xs[] = { 0.0f, 1.0f, -1.0f, 5.5f, -5.5f, 100.0f, -100.0f };
    float ys[] = { 0.3f, 1.0f, -1.0f, 2.0f, 3.14159265f };
    int nx = sizeof(xs) / sizeof(xs[0]);
    int ny = sizeof(ys) / sizeof(ys[0]);

    for (int i = 0; i < nx; i++) {
        for (int j = 0; j < ny; j++) {
            emit(xs[i], ys[j]);
        }
    }
}

/* 5. Large numerator */
static void test_large_numerator(void)
{
    float divisors[] = { 1.0f, 2.0f, 10.0f, 0.5f };
    int nd = sizeof(divisors) / sizeof(divisors[0]);

    for (int j = 0; j < nd; j++) {
        emit(1000.0f, divisors[j]);
        emit(-1000.0f, divisors[j]);
        emit(1.0e10f, divisors[j]);
        emit(-1.0e10f, divisors[j]);
        emit(FLT_MAX, divisors[j]);
        emit(-FLT_MAX, divisors[j]);
    }
}

/* 6. Various divisors */
static void test_divisors(void)
{
    float numerators[] = { 10.0f, 100.0f, -10.0f, -100.0f };
    float divisors[] = { 0.5f, 1.0f, 2.0f, 3.0f, 7.0f, 10.0f, 15.0f };

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 7; j++) {
            emit(numerators[i], divisors[j]);
        }
    }
}

/* 7. Negative values with sign handling */
static void test_signs(void)
{
    float vals[] = { 1.0f, 2.0f, 3.0f, 5.0f, 10.0f };
    int n = sizeof(vals) / sizeof(vals[0]);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            emit(vals[i], vals[j]);
            emit(-vals[i], vals[j]);
            emit(vals[i], -vals[j]);
            emit(-vals[i], -vals[j]);
        }
    }
}

/* 8. Edge cases: small remainder */
static void test_edge_remainder(void)
{
    emit(10.001f, 1.0f);
    emit(10.0001f, 1.0f);
    emit(10.99f, 1.0f);
    emit(10.999f, 1.0f);
    emit(-10.001f, 1.0f);
    emit(-10.0001f, 1.0f);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_exact();
    test_remainder();
    test_large_numerator();
    test_divisors();
    test_signs();
    test_edge_remainder();
    return 0;
}

