/*
 * fabsf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fabsf  (test_fabsf_opt.elf)
 *   2. Linked with toolchain's default fabsf        (test_fabsf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = fabsf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values (denormals and subnormals) */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u); /* -min denorm */
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u); /* -mid denorm */
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu); /* -max denorm */
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
}

/* 3. Positive and negative pairs */
static void test_pairs(void)
{
    float vals[] = {
        0.1f, 0.5f, 1.0f, 1.5f, 2.0f, 3.0f,
        0.78539816f, 1.57079633f, 3.14159265f, 6.28318531f,
        10.0f, 100.0f, 1000.0f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        emit(vals[i]);
        emit(-vals[i]);
    }
}

/* 4. Large values */
static void test_large(void)
{
    float vals[] = {
        1.0e10f, -1.0e10f,
        1.0e20f, -1.0e20f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Values near zero */
static void test_near_zero(void)
{
    float vals[] = {
        0.0f, -0.0f,
        1.0e-40f, -1.0e-40f,
        1.0e-30f, -1.0e-30f,
        1.0e-20f, -1.0e-20f,
        1.0e-10f, -1.0e-10f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Worst-case bit patterns */
static void test_hard(void)
{
    float cases[] = {
        0.125f, -0.125f,
        0.25f, -0.25f,
        0.375f, -0.375f,
        0.625f, -0.625f,
        0.75f, -0.75f,
        0.875f, -0.875f,
        0.999f, -0.999f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++)
        emit(cases[i]);
}

/* 7. Sweep [-4*pi, 4*pi] in 200 steps */
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = (2.0f * hi) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [-1, 1] every 4194304 ULP (~500 cases) */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf800000u; /* -1.0 */
    uint32_t end = 0x3f800000u;   /* 1.0 */

    for (uint32_t b = start; b <= end; b += 2097152)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_pairs();
    test_large();
    test_near_zero();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

