static void test_denormals(void)
{
    emit_u(0x00000001u); /* min positive denorm */
    emit_u(0x80000001u); /* min negative denorm */
    emit_u(0x00400000u); /* mid positive denorm */
    emit_u(0x80400000u); /* mid negative denorm */
    emit_u(0x007fffffu); /* max positive denorm */
    emit_u(0x807fffffu); /* max negative denorm */
}

/* 3. Normal values (FP_NORMAL) */
static void test_normal(void)
{
    /* Smallest normal values */
    emit(FLT_MIN);
    emit(-FLT_MIN);

    /* Small positive/negative */
    float vals[] = {
        0.5f, -0.5f,
        1.0f, -1.0f,
        1.5f, -1.5f,
        2.0f, -2.0f,
        10.0f, -10.0f,
        100.0f, -100.0f,
        1000.0f, -1000.0f,
